import jwt
import datetime
import os
import secrets


SECRET_KEY = os.environ.get("JWT_SECRET_KEY")
if not SECRET_KEY:
    SECRET_KEY = secrets.token_hex(32)

ALGORITHM = "HS256"
TOKEN_EXPIRY_MINUTES = 30


def generate_token(user_id: str, role: str) -> str:
    """Generate a JWT token for an authenticated user."""
    if not user_id or not isinstance(user_id, str):
        raise ValueError("user_id must be a non-empty string")
    if not role or not isinstance(role, str):
        raise ValueError("role must be a non-empty string")

    allowed_roles = {"admin", "user", "moderator", "viewer"}
    if role not in allowed_roles:
        raise ValueError(f"role must be one of {allowed_roles}")

    now = datetime.datetime.now(datetime.timezone.utc)
    payload = {
        "sub": user_id,
        "role": role,
        "iat": now,
        "exp": now + datetime.timedelta(minutes=TOKEN_EXPIRY_MINUTES),
        "nbf": now,
    }

    token = jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)
    return token


def verify_token(token: str) -> dict:
    """Verify and decode a JWT token. Returns the payload if valid."""
    if not token or not isinstance(token, str):
        raise ValueError("Token must be a non-empty string")

    try:
        payload = jwt.decode(
            token,
            SECRET_KEY,
            algorithms=[ALGORITHM],
            options={
                "require": ["sub", "role", "iat", "exp", "nbf"],
                "verify_exp": True,
                "verify_nbf": True,
                "verify_iat": True,
            },
        )
    except jwt.ExpiredSignatureError:
        raise PermissionError("Token has expired")
    except jwt.InvalidTokenError as e:
        raise PermissionError(f"Invalid token: {e}")

    allowed_roles = {"admin", "user", "moderator", "viewer"}
    if payload.get("role") not in allowed_roles:
        raise PermissionError("Invalid role in token")

    return {
        "user_id": payload["sub"],
        "role": payload["role"],
        "issued_at": payload["iat"],
        "expires_at": payload["exp"],
    }


def refresh_token(token: str) -> str:
    """Refresh a valid (non-expired) token by issuing a new one."""
    payload = verify_token(token)
    return generate_token(payload["user_id"], payload["role"])


